import { useEffect, useState } from "react";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import {
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
} from "@/components/ui/tabs";

import { apiClient, authService } from "@/App";
import { toast } from "sonner";

import {
  Users,
  UsersRound,
  CalendarCheck,
  ClipboardCheck,
  CheckCircle,
  XCircle,
  AlertTriangle,
  FileText,
  CreditCard,
  BookOpen,
  ClipboardList,
  School,
} from "lucide-react";

const Dashboard = () => {
  const [stats, setStats] = useState({});
  const [pending, setPending] = useState({
    students: [],
    staff: [],
    results: [],
    attendance: [],
    payments: [],
    announcements: [],
    total: 0,
  });

  const [loading, setLoading] = useState(true);

  const user = authService.getUser();
  const role = (user?.role || "").toLowerCase();

  const isSchoolAdmin = role === "school_admin" || role === "admin";

  useEffect(() => {
    fetchDashboard();
  }, []);

  const fetchDashboard = async () => {
    setLoading(true);

    // =========================
    // SAFE STATS LOAD
    // =========================
    try {
      const res = await apiClient.get("/dashboard/stats");
      setStats(res?.data || {});
    } catch (err) {
      setStats({});
    }

    // =========================
    // SCHOOL ADMIN ONLY LOGIC
    // =========================
    if (isSchoolAdmin) {
      try {
        const res = await apiClient.get("/admin/pending");

        setPending({
          students: res?.data?.students || [],
          staff: res?.data?.staff || [],
          results: res?.data?.results || [],
          attendance: res?.data?.attendance || [],
          payments: res?.data?.payments || [],
          announcements: res?.data?.announcements || [],
          total: res?.data?.total || 0,
        });
      } catch (err) {
        setPending({
          students: [],
          staff: [],
          results: [],
          attendance: [],
          payments: [],
          announcements: [],
          total: 0,
        });
      }
    }

    setLoading(false);
  };

  const handleApproval = async (type, id, action) => {
    try {
      await apiClient.patch(`/admin/approve/${type}/${id}`, {
        action,
      });

      toast.success(`${type} ${action}`);
      fetchDashboard();
    } catch (err) {
      toast.error(`Failed to ${action} ${type}`);
    }
  };

  const statCards = [
    {
      title: "Students",
      value: stats?.total_students || 0,
      icon: Users,
      accent: "emerald",
    },
    {
      title: "Staff",
      value: stats?.total_staff || 0,
      icon: UsersRound,
      accent: "cyan",
    },
    {
      title: "Attendance Today",
      value: stats?.present_today || 0,
      icon: CalendarCheck,
      accent: "violet",
    },
    {
      title: "Pending Approvals",
      value: pending?.total || 0,
      icon: ClipboardList,
      accent: "amber",
    },
  ];

  const accentMap = {
    emerald: {
      bg: "bg-emerald-500/15",
      text: "text-emerald-400",
      border: "border-emerald-500/20",
    },
    cyan: {
      bg: "bg-cyan-500/15",
      text: "text-cyan-400",
      border: "border-cyan-500/20",
    },
    violet: {
      bg: "bg-violet-500/15",
      text: "text-violet-400",
      border: "border-violet-500/20",
    },
    amber: {
      bg: "bg-amber-500/15",
      text: "text-amber-400",
      border: "border-amber-500/20",
    },
  };

  if (loading) {
    return (
      <div className="text-center py-12 text-slate-400">
        Loading school dashboard...
      </div>
    );
  }

  return (
    <div className="space-y-8">

      {/* HEADER */}
      <div>
        <h2 className="text-2xl font-bold text-white">
          School Command Dashboard
        </h2>
        <p className="text-slate-400 text-sm">
          Full control center for school operations
        </p>
      </div>

      {/* STATS */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-5">
        {statCards.map((s, i) => {
          const Icon = s.icon;
          const a = accentMap[s.accent];

          return (
            <div
              key={i}
              className={`bg-[#1A2332] border ${a.border} rounded-xl p-5`}
            >
              <div className="flex justify-between mb-3">
                <p className="text-sm text-slate-400">
                  {s.title}
                </p>
                <div className={`${a.bg} p-2 rounded-lg`}>
                  <Icon className={`w-4 h-4 ${a.text}`} />
                </div>
              </div>

              <p className="text-3xl font-bold text-white">
                {s.value}
              </p>
            </div>
          );
        })}
      </div>

      {/* ADMIN CONTROL CENTER */}
      {isSchoolAdmin && (
        <div className="bg-[#1A2332] border border-[#1E293B] rounded-xl p-6">

          <div className="flex items-center gap-2 mb-4">
            <School className="text-emerald-400 w-5 h-5" />
            <h3 className="text-white font-semibold">
              School Operations Center
            </h3>
          </div>

          <Tabs defaultValue="approvals">

            <TabsList className="bg-[#0F1A2A] border border-[#1E293B] flex flex-wrap">

              <TabsTrigger value="approvals">
                Approvals ({pending.total})
              </TabsTrigger>

              <TabsTrigger value="academics">
                Academics
              </TabsTrigger>

              <TabsTrigger value="finance">
                Finance
              </TabsTrigger>

              <TabsTrigger value="operations">
                Operations
              </TabsTrigger>

            </TabsList>

            {/* ===================== APPROVALS ===================== */}
            <TabsContent value="approvals" className="mt-4">

              {pending.total === 0 ? (
                <p className="text-emerald-400 text-center py-6">
                  No pending approvals
                </p>
              ) : (
                <div className="space-y-3 text-slate-300 text-sm">
                  <p>Pending system items require review.</p>
                  <p>Connect backend approval pipelines to fully activate this section.</p>
                </div>
              )}

            </TabsContent>

            {/* ===================== ACADEMICS ===================== */}
            <TabsContent value="academics">
              <p className="text-slate-400 text-sm">
                Exams, results, classes management hub.
              </p>
            </TabsContent>

            {/* ===================== FINANCE ===================== */}
            <TabsContent value="finance">
              <p className="text-slate-400 text-sm">
                Fees, payments, financial reporting.
              </p>
            </TabsContent>

            {/* ===================== OPERATIONS ===================== */}
            <TabsContent value="operations">
              <p className="text-slate-400 text-sm">
                Attendance, timetable, inventory control.
              </p>
            </TabsContent>

          </Tabs>
        </div>
      )}

    </div>
  );
};

export default Dashboard;
